'use client';

import { Mesh, Program, Renderer, Triangle, Vec3 } from 'ogl';
import { useDeferredValue, useEffect, useRef } from 'react';

import { cn } from '@/lib/utils';
import { mergeRefs, useInView, usePrefersReducedMotion } from '@/lib/containment';

// ─── Types ────────────────────────────────────────────────────────────────────

export type PrismaticOrbProps = {
	className?: string;
	/** Hot-pink gradient zone (6-char hex). */
	color1?: string;
	/** Cyan gradient zone (6-char hex). */
	color2?: string;
	/** Violet gradient zone (6-char hex). */
	color3?: string;
	/** Gold gradient zone (6-char hex). */
	color4?: string;
	/** Orb hue rotation in degrees (0 = defaults). */
	hue?: number;
	/** Orb drift speed multiplier. */
	speed?: number;
	/** React 19: passed as a plain prop — no forwardRef needed. */
	ref?: React.Ref<HTMLDivElement>;
};

// ─── GLSL — ogl Orb shader (adapted from react-bits) ────────────────────────

const VERT = /* glsl */ `
  precision highp float;
  attribute vec2 position;
  attribute vec2 uv;
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = vec4(position, 0.0, 1.0);
  }
`;

const FRAG = /* glsl */ `
  precision highp float;

  uniform float iTime;
  uniform vec3  iResolution;
  uniform float hue;
  uniform float rot;
  uniform float uSpeed;
  varying vec2  vUv;

  vec3 rgb2yiq(vec3 c) {
    return vec3(
      dot(c, vec3(0.299, 0.587, 0.114)),
      dot(c, vec3(0.596, -0.274, -0.322)),
      dot(c, vec3(0.211, -0.523, 0.312))
    );
  }
  vec3 yiq2rgb(vec3 c) {
    return vec3(
      c.x + 0.956 * c.y + 0.621 * c.z,
      c.x - 0.272 * c.y - 0.647 * c.z,
      c.x - 1.106 * c.y + 1.703 * c.z
    );
  }
  vec3 adjustHue(vec3 color, float hueDeg) {
    float a = hueDeg * 3.14159265 / 180.0;
    vec3 yiq = rgb2yiq(color);
    float i = yiq.y * cos(a) - yiq.z * sin(a);
    float q = yiq.y * sin(a) + yiq.z * cos(a);
    return yiq2rgb(vec3(yiq.x, i, q));
  }

  vec3 hash33(vec3 p3) {
    p3 = fract(p3 * vec3(0.1031, 0.11369, 0.13787));
    p3 += dot(p3, p3.yxz + 19.19);
    return -1.0 + 2.0 * fract(vec3(p3.x + p3.y, p3.x + p3.z, p3.y + p3.z) * p3.zyx);
  }
  float snoise3(vec3 p) {
    const float K1 = 0.333333333;
    const float K2 = 0.166666667;
    vec3 i  = floor(p + (p.x + p.y + p.z) * K1);
    vec3 d0 = p - (i - (i.x + i.y + i.z) * K2);
    vec3 e  = step(vec3(0.0), d0 - d0.yzx);
    vec3 i1 = e * (1.0 - e.zxy);
    vec3 i2 = 1.0 - e.zxy * (1.0 - e);
    vec3 d1 = d0 - (i1 - K2);
    vec3 d2 = d0 - (i2 - K1);
    vec3 d3 = d0 - 0.5;
    vec4 h  = max(0.6 - vec4(dot(d0,d0), dot(d1,d1), dot(d2,d2), dot(d3,d3)), 0.0);
    vec4 n  = h*h*h*h * vec4(
      dot(d0, hash33(i)),
      dot(d1, hash33(i + i1)),
      dot(d2, hash33(i + i2)),
      dot(d3, hash33(i + 1.0))
    );
    return dot(vec4(31.316), n);
  }

  vec4 extractAlpha(vec3 col) {
    float a = max(max(col.r, col.g), col.b);
    return vec4(col / (a + 1e-5), a);
  }

  const vec3 BASE1 = vec3(0.612, 0.263, 0.996);
  const vec3 BASE2 = vec3(0.298, 0.761, 0.914);
  const vec3 BASE3 = vec3(0.063, 0.078, 0.600);
  const float INNER_R = 0.6;
  const float NOISE_S = 0.65;

  float light1(float i, float a, float d) { return i / (1.0 + d * a); }
  float light2(float i, float a, float d) { return i / (1.0 + d * d * a); }

  vec4 draw(vec2 uv) {
    vec3 c1 = adjustHue(BASE1, hue);
    vec3 c2 = adjustHue(BASE2, hue);
    vec3 c3 = adjustHue(BASE3, hue);

    float ang    = atan(uv.y, uv.x);
    float len    = length(uv);
    float invLen = len > 0.0 ? 1.0 / len : 0.0;

    float n0 = snoise3(vec3(uv * NOISE_S, iTime * uSpeed * 0.5)) * 0.5 + 0.5;
    float r0 = mix(mix(INNER_R, 1.0, 0.4), mix(INNER_R, 1.0, 0.6), n0);
    float d0 = distance(uv, r0 * invLen * uv);
    float v0 = light1(1.0, 10.0, d0);
    v0 *= smoothstep(r0 * 1.05, r0, len);
    v0 *= mix(smoothstep(r0 * 0.8, r0 * 0.95, len), 1.0, 0.0);

    float cl = cos(ang + iTime * uSpeed * 2.0) * 0.5 + 0.5;
    float a  = iTime * uSpeed * -1.0;
    vec2  pos = vec2(cos(a), sin(a)) * r0;
    float dv  = distance(uv, pos);
    float v1  = light2(1.5, 5.0, dv) * light1(1.0, 50.0, d0);

    float v2 = smoothstep(1.0, mix(INNER_R, 1.0, n0 * 0.5), len);
    float v3 = smoothstep(INNER_R, mix(INNER_R, 1.0, 0.5), len);

    vec3 colBase = mix(c1, c2, cl);
    vec3 darkCol = (mix(c3, colBase, v0) + v1) * v2 * v3;
    darkCol = clamp(darkCol, 0.0, 1.0);

    return extractAlpha(darkCol);
  }

  void main() {
    vec2  center = iResolution.xy * 0.5;
    float size   = min(iResolution.x, iResolution.y);
    vec2  uv     = (vUv * iResolution.xy - center) / size * 2.0;

    float s = sin(rot); float c = cos(rot);
    uv = vec2(c * uv.x - s * uv.y, s * uv.x + c * uv.y);

    // Slow drift across the canvas — orb wanders rather than staying centred
    float driftT = iTime * uSpeed * 0.18;
    uv.x += sin(driftT * 0.7 + 1.1) * 0.35;
    uv.y += sin(driftT * 0.5 + 2.4) * 0.28;

    vec4 col = draw(uv);
    gl_FragColor = vec4(col.rgb * col.a, col.a);
  }
`;

// ─── Helpers ──────────────────────────────────────────────────────────────────

function hexToRgba(hex: string, alpha: number): string {
	const h = hex.replace('#', '');
	const r = parseInt(h.slice(0, 2), 16);
	const g = parseInt(h.slice(2, 4), 16);
	const b = parseInt(h.slice(4, 6), 16);
	return `rgba(${r},${g},${b},${alpha})`;
}

// ─── Component ────────────────────────────────────────────────────────────────

/**
 * CSS prismatic multi-ellipse gradient (pattern-craft `northern-aurora` /
 * `prismatic-aurora-burst` style) as a permanent base layer — hot-pink, cyan,
 * violet, and gold bleeding into black — with an ogl WebGL Orb that slowly
 * wanders across the canvas on a Lissajous drift path.
 *
 * `mix-blend-mode: screen` on the WebGL canvas causes the orb to act as a
 * concentrated moving light source that amplifies whichever colour zone it
 * passes through, giving the impression the static gradient is alive.
 *
 * - Layer 1 (bottom): 4-zone CSS radial gradient — instant, zero JS.
 * - Layer 2 (top):    ogl WebGL wandering Orb — pauses off-screen.
 * - Reduced-motion:   CSS gradient only.
 *
 * React 19: `ref` accepted as a plain prop — no `forwardRef` wrapper.
 */
export function PrismaticOrb({
	ref,
	className,
	color1 = '#ff1493',
	color2 = '#00ffff',
	color3 = '#8b2be2',
	color4 = '#ffd700',
	hue = 0,
	speed = 1.0,
}: PrismaticOrbProps) {
	const reducedMotion = usePrefersReducedMotion();
	const { ref: inViewRef, inView } = useInView();
	const rootRef = useRef<HTMLDivElement>(null);
	const orbRef = useRef<HTMLDivElement>(null);

	const inViewMut = useRef(inView);
	useEffect(() => {
		inViewMut.current = inView;
	}, [inView]);

	const dHue = useDeferredValue(hue);
	const dSpeed = useDeferredValue(speed);

	const hueRef = useRef(dHue);
	const speedRef = useRef(dSpeed);
	useEffect(() => {
		hueRef.current = dHue;
		speedRef.current = dSpeed;
	}, [dHue, dSpeed]);

	// ogl WebGL Orb — restarts only when reducedMotion changes
	useEffect(() => {
		if (reducedMotion) return;

		const container = orbRef.current;
		if (!container) return;

		const renderer = new Renderer({ alpha: true, premultipliedAlpha: false });
		const gl = renderer.gl;
		gl.clearColor(0, 0, 0, 0);
		container.appendChild(gl.canvas);

		const geometry = new Triangle(gl);
		const program = new Program(gl, {
			vertex: VERT,
			fragment: FRAG,
			uniforms: {
				iTime: { value: 0 },
				iResolution: { value: new Vec3(gl.canvas.width, gl.canvas.height, 1) },
				hue: { value: hueRef.current },
				rot: { value: 0 },
				uSpeed: { value: speedRef.current },
			},
		});
		const mesh = new Mesh(gl, { geometry, program });

		function resize() {
			if (!container) return;
			const dpr = window.devicePixelRatio || 1;
			const w = container.clientWidth;
			const h = container.clientHeight;
			renderer.setSize(w * dpr, h * dpr);
			gl.canvas.style.width = `${w}px`;
			gl.canvas.style.height = `${h}px`;
			program.uniforms.iResolution.value.set(gl.canvas.width, gl.canvas.height, 1);
		}
		window.addEventListener('resize', resize);
		resize();

		let rafId: number;
		let currentRot = 0;
		let lastTime = 0;

		const update = (t: number) => {
			rafId = requestAnimationFrame(update);
			if (!inViewMut.current) return;

			const dt = Math.min((t - lastTime) * 0.001, 0.05);
			lastTime = t;

			program.uniforms.iTime.value = t * 0.001;
			program.uniforms.hue.value = hueRef.current;
			program.uniforms.uSpeed.value = speedRef.current;
			currentRot += dt * 0.15 * speedRef.current;
			program.uniforms.rot.value = currentRot;

			renderer.render({ scene: mesh });
		};
		rafId = requestAnimationFrame(update);

		return () => {
			cancelAnimationFrame(rafId);
			window.removeEventListener('resize', resize);
			if (container.contains(gl.canvas)) container.removeChild(gl.canvas);
			gl.getExtension('WEBGL_lose_context')?.loseContext();
		};
	}, [reducedMotion]);

	// CSS base: northern-aurora / prismatic-aurora-burst style gradient
	const baseStyle: React.CSSProperties = {
		background: [
			`radial-gradient(ellipse 130% 85% at 72% 18%, ${hexToRgba(color1, 0.22)} 0%, transparent 52%)`,
			`radial-gradient(ellipse 110% 65% at 28% 12%, ${hexToRgba(color2, 0.16)} 0%, transparent 62%)`,
			`radial-gradient(ellipse 95% 75% at 52% 8%, ${hexToRgba(color3, 0.24)} 0%, transparent 67%)`,
			`radial-gradient(ellipse 120% 55% at 82% 32%, ${hexToRgba(color4, 0.10)} 0%, transparent 42%)`,
			'radial-gradient(ellipse 70% 50% at 50% 50%, rgba(255,255,255,0.04) 0%, transparent 50%)',
			'#000000',
		].join(', '),
	};

	return (
		<div
			ref={mergeRefs(ref, inViewRef, rootRef)}
			className={cn('relative h-full w-full overflow-hidden', className)}
		>
			{/* Layer 1 (bottom): CSS prismatic gradient — pattern-craft northern-aurora style */}
			<div className="pointer-events-none absolute inset-0" style={baseStyle} aria-hidden />

			{/* Layer 2 (top): WebGL Orb wandering across the gradient field */}
			{!reducedMotion && (
				<div
					ref={orbRef}
					className="pointer-events-none absolute inset-0"
					style={{ mixBlendMode: 'screen' }}
					aria-hidden
				/>
			)}
		</div>
	);
}
